from collections import defaultdict, deque

def max_weighted_path(n, edges, weights, k):
    graph = defaultdict(list)
    indeg = [0]*n
    for u,v in edges:
        graph[u].append(v)
        indeg[v] += 1

    # Topological order
    q = deque([0]) if indeg[0] == 0 else deque()
    topo = []
    visited = [False]*n
    while q:
        u = q.popleft()
        topo.append(u)
        for v in graph[u]:
            indeg[v] -= 1
            if indeg[v] == 0:
                q.append(v)

    if topo[0] != 0:
        # no path starts at 0
        return -1

    # dp[node] = dict {edges_used: max_weight_sum}
    # Initialize dp for node 0
    dp = [defaultdict(lambda: float('-inf')) for _ in range(n)]
    dp[0][0] = weights[0]

    for u in topo:
        for edges_used, curr_sum in dp[u].items():
            if edges_used == k:
                continue
            for v in graph[u]:
                nxt_edges = edges_used + 1
                nxt_sum = curr_sum + weights[v]
                if dp[v][nxt_edges] < nxt_sum:
                    dp[v][nxt_edges] = nxt_sum

    max_sum = max(dp[n-1].values(), default=float('-inf'))
    return max_sum if max_sum != float('-inf') else -1

