def max_weighted_path(n, edges, weights, k):
    graph = [[] for _ in range(n)]
    for u,v in edges:
        graph[u].append(v)

    memo = {}

    def dfs(u, rem):
        if rem < 0:
            return float('-inf')
        if u == n-1:
            return weights[u]
        if (u, rem) in memo:
            return memo[(u, rem)]

        best = float('-inf')
        for v in graph[u]:
            val = dfs(v, rem-1)
            if val != float('-inf'):
                best = max(best, val + weights[u])
        memo[(u, rem)] = best
        return best

    res = dfs(0, k)
    return res if res != float('-inf') else -1

