def max_weighted_path(n, edges, weights, k):
    graph = [[] for _ in range(n)]
    indeg = [0]*n
    for u,v in edges:
        graph[u].append(v)
        indeg[v] += 1

    q = deque()
    for i in range(n):
        if indeg[i] == 0:
            q.append(i)

    # dp[node] = (max_sum, min_edges)
    dp = [(float('-inf'), float('inf')) for _ in range(n)]
    dp[0] = (weights[0], 0)

    while q:
        u = q.popleft()
        for v in graph[u]:
            curr_sum, curr_len = dp[u]
            if curr_len + 1 <= k:
                new_sum = curr_sum + weights[v]
                old_sum, old_len = dp[v]
                if new_sum > old_sum or (new_sum == old_sum and curr_len+1 < old_len):
                    dp[v] = (new_sum, curr_len+1)
            indeg[v] -= 1
            if indeg[v] == 0:
                q.append(v)

    max_sum, length = dp[n-1]
    return max_sum if max_sum != float('-inf') else -1

