def max_weighted_path(n, edges, weights, k):
    graph = [[] for _ in range(n)]
    indeg = [0]*n
    for u,v in edges:
        graph[u].append(v)
        indeg[v] += 1

    q = deque([0])
    dp = [dict() for _ in range(n)]
    dp[0][0] = weights[0]

    # Topological order with standard Kahn's algorithm
    order = []
    indeg2 = indeg[:]
    q2 = deque([i for i in range(n) if indeg2[i] == 0])
    while q2:
        u = q2.popleft()
        order.append(u)
        for v in graph[u]:
            indeg2[v] -= 1
            if indeg2[v] == 0:
                q2.append(v)

    for u in order:
        for length, val in dp[u].items():
            if length == k:
                continue
            for v in graph[u]:
                nl = length + 1
                nv = val + weights[v]
                if nl in dp[v]:
                    if dp[v][nl] < nv:
                        dp[v][nl] = nv
                else:
                    dp[v][nl] = nv

    if not dp[n-1]:
        return -1
    return max(dp[n-1].values())

