        cat = best_cats[0]
        conf = base_conf.get(cat, 0.7)
        return cat, conf

    # Build similarity graph based on Jaccard similarity of token sets
    def jaccard_sim(s1, s2):
        set1 = set(tokenize(s1.lower()))
        set2 = set(tokenize(s2.lower()))
        if not set1 or not set2:
            return 0.0
        return len(set1 & set2)/len(set1 | set2)

    def build_graph(sentences):
        n = len(sentences)
        graph = [[] for _ in range(n)]
        for i in range(n):
            for j in range(i+1, n):
                sim = jaccard_sim(sentences[i], sentences[j])
                if sim > 0.2:
                    graph[i].append((j, sim))
                    graph[j].append((i, sim))
        return graph

    # Smooth confidence by averaging with neighbors having same label
    def smooth_confidence(labels, confidences, graph, rounds=2):
        n = len(labels)
