from typing import List, Tuple
import re

def classify_sentences(documents: List[str], categories: List[str]) -> List[List[Tuple[str, float]]]:
    # Sentence splitter: split on ., ?, ! (common in multiple languages)
    sentence_splitter_re = re.compile(r'(?<=[.!?])\s+')

    # Keywords for categories (includes multilingual variants)
    category_keywords = {
        'enquiry': ['can', 'could', 'would', 'should', 'tell', 'provide', 'please', 'is', 'are', 'what', 'how', 'when', 'where', 'quel', 'quelle', 'was', 'wie', 'wann', 'wo', 'bitte', 'ist', 'sind', 'can', 'may', 'return', 'invoice', 'support', 'warranty'],
        'purchase': ['buy', 'purchase', 'want', 'order', 'acheter', 'kaufen', 'bestellen', 'acheter', 'souhaite', 'wants', 'want', 'items'],
        'negative_feedback': ['late', 'delay', 'delayed', 'hate', 'disappointed', 'bad', 'worst', 'déçu', 'mauvais', 'schlecht', 'verspätet', 'unzufrieden', 'hassen', 'cancel', 'storniert'],
        'positive_feedback': ['great', 'good', 'happy', 'love', 'excellent', 'fantastic', 'merci', 'bien', 'glücklich', 'großartig', 'fantastisch', 'helpful', 'support', 'happy']
    }

    def tokenize(s):
        return set(re.findall(r'\b\w+\b', s.lower()))

    # Initial score based on fraction of tokens matching category keywords
    def initial_scores(tokens):
        scores = {}
        for cat in categories:
            kws = category_keywords.get(cat, [])
            if not kws:
                scores[cat] = 0
                continue
            count = sum(1 for t in tokens if t in kws)
            scores[cat] = count / max(len(kws),1)
        total = sum(scores.values())
        if total == 0:
            # uniform
            scores = {c: 1/len(categories) for c in categories}
        else:
            scores = {c: s/total for c,s in scores.items()}
        return scores

    all_sentences = []
    doc_sentence_indices = []
    for doc in documents:
        sents = [s.strip() for s in sentence_splitter_re.split(doc) if s.strip()]
        doc_sentence_indices.append((len(all_sentences), len(all_sentences)+len(sents)))
        all_sentences.extend(sents)

    tokens_list = [tokenize(s) for s in all_sentences]
    init_scores_list = [initial_scores(toks) for toks in tokens_list]

    n = len(all_sentences)

    # Build graph by Jaccard similarity > threshold
    def jaccard(a, b):
        if not a or not b:
            return 0.0
        return len(a & b) / len(a | b)

    threshold = 0.3
    adjacency = [[] for _ in range(n)]
    for i in range(n):
        for j in range(i+1, n):
            sim = jaccard(tokens_list[i], tokens_list[j])
            if sim > threshold:
                adjacency[i].append((j, sim))
                adjacency[j].append((i, sim))

    # Label smoothing: update confidence scores over graph 2 iterations
    scores = init_scores_list
    for _ in range(2):
        new_scores = []
        for i in range(n):
            acc = {cat: scores[i][cat] for cat in categories}
            weight_sum = 1.0
            for (nbr, w) in adjacency[i]:
                weight_sum += w
                for cat in categories:
                    acc[cat] += w * scores[nbr][cat]
            for cat in categories:
                acc[cat] /= weight_sum
            new_scores.append(acc)
        scores = new_scores

    # Map scores to confidence in [0.6, 0.85]
    def scale_conf(x):
        return round(0.6 + 0.25*x, 2)

    results = []
    for start, end in doc_sentence_indices:
        doc_res = []
        for i in range(start, end):
            sc = scores[i]
            cat = max(sc, key=sc.get)
            conf = scale_conf(sc[cat])
            doc_res.append((cat, conf))
        results.append(doc_res)

    return results
